SELECT ?team ?wins ?label WHERE {
  ?team p:P1355 ?statement .
  ?statement ps:P1355 ?wins .
  ?statement pq:P765 wd:Q28127991 .
  OPTIONAL { ?team rdfs:label ?label . FILTER (langMatches(lang(?label), "en")) }
} ORDER BY DESC(?wins) LIMIT 1

